def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    sorted_words = []

    # Group words by their lengths
    length_dict = {}
    for word in words:
        length = len(word)
        if length not in length_dict:
            length_dict[length] = []
        length_dict[length].append(word)

    # Sort each group of words reverse-alphabetically and add to sorted_words list
    for length in sorted(length_dict):
        sorted_words.extend(sorted(length_dict[length], reverse=True))

    # Return the k-th word if within range, otherwise None
    if k <= len(sorted_words):
        return sorted_words[k - 1]
    else:
        return None

# Edge Case: Empty list of words
print(kth_ordered([], 3))  # Output: None
